module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output mul_en_out,
    output [15:0] mul_out,
    input mul_en_in,
    output reg mul_en_out_reg,
    output mul_en_out,
    input mul_a,
    output reg mul_a_reg,
    output reg mul_a_reg,
    input mul_b,
    output reg mul_b_reg,
    output reg mul_b_reg,
    input mul_a_reg,
    input mul_b_reg,
    output temp[0],
    input mul_a_reg,
    input mul_b_reg,
    output temp[1],
    input mul_a_reg,
    input mul_b_reg,
    output temp[2],
    input mul_a_reg
);

parameter N = 8;

// Internal wires and registers
reg [N-1:0] mul_a_reg, mul_b_reg;
reg [2*N-1:0] mul_out_reg;
reg mul_en_out_reg;

// Input control
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
        mul_en_out_reg <= 0;
    end else if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
        mul_en_out_reg <= 1'b1;
    end else begin
        mul_en_out_reg <= 1'b0;
    end
end

assign mul_en_out = mul_en_out_reg;

// Partial product generation
wire [N-1:0] partial_products[N-1:0];
genvar i;
generate
    for (i = 0; i < N; i = i + 1) begin: partial_product_gen
        assign partial_products[i] = mul_b_reg[i] ? (mul_a_reg << i) : 0;
    end
endgenerate

// Partial product addition
wire [2*N-1:0] sum[N-1:0];
assign sum[0] = {8'b0, partial_products[0]};
genvar j;
generate
    for (j = 1; j < N; j = j + 1) begin: partial_product_add
        assign sum[j] = {sum[j-1][2*N-1:N], sum[j-1][N-1:0]} + {8'b0, partial_products[j]};
    end
endgenerate

// Final product calculation
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out_reg <= 0;
    end else begin
        mul_out_reg <= sum[N-1];
    end
end

assign mul_out = mul_out_reg;

endmodule
